from core.step_compiler import StepCompiler


class APIGenerator:
    def __init__(self, data_list):
        self.data_list = data_list

    def generate(self):
        code = ""

        # IMPORTS
        code += """
// Auto-generated by MadiLang v0.3
import express from 'express';
import prisma from './prisma';
import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';

const app = express();
app.use(express.json());
"""

        # GLOBAL MIDDLEWARE
        code += """
const authMiddleware = (req, res, next) => {
  const token = req.headers.authorization;

  if (!token) {
    return res.status(401).json({ error: "Unauthorized" });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET || 'dev_secret');
    req.user = decoded;
    next();
  } catch (err) {
    return res.status(401).json({ error: "Invalid token" });
  }
};
"""

        compiler = StepCompiler()

        # INTENTS LOOP
        for data in self.data_list:

            entity = data["entity"]
            path = data["path"]
            method = data["method"].lower()
            inputs = data["inputs"]
            steps = compiler.compile(data["steps"])

            has_auth = any(s["type"] == "auth_required" for s in steps)
            roles = [s["role"] for s in steps if s["type"] == "role_guard"]

            # ROUTE START
            if has_auth:
                code += f"\napp.{method}('{path}', authMiddleware, async (req, res) => {{\n"
            else:
                code += f"\napp.{method}('{path}', async (req, res) => {{\n"

            # INPUTS
            if inputs:
                code += f"  const {{ {', '.join(inputs)} }} = req.body;\n"
                code += "  if (!" + " || !".join(inputs) + ") {\n"
                code += "    return res.status(400).json({ error: 'Missing fields' });\n"
                code += "  }\n"

            # ROLE GUARD
            for role in roles:
                code += f"""
  if (req.user.role !== '{role}') {{
    return res.status(403).json({{ error: 'Forbidden: requires {role}' }});
  }}
"""

            # STEP EXECUTION
            for step in steps:

                t = step["type"]

                if t == "find":
                    code += f"""
  const {step['as']} = await prisma.{step['entity'].lower()}.findUnique({{
    where: {{ {step['field']}: {step['field']} }}
  }});
"""

                elif t == "if_not_found":
                    code += f"""
  if (!{step['var']}) {{
    return res.status(404).json({{ error: '{step['var']} not found' }});
  }}
"""

                elif t == "if_exists":
                    code += f"""
  if ({step['field']}) {{
    return res.status(400).json({{ error: '{step['field']} already exists' }});
  }}
"""

                elif t == "password_mismatch":
                    code += f"""
  const valid = await bcrypt.compare(password, {step['var']}.{step['field']});
  if (!valid) {{
    return res.status(401).json({{ error: 'Invalid credentials' }});
  }}
"""

                elif t == "create":
                    code += f"""
  const result = await prisma.{entity.lower()}.create({{
    data: {{
"""
                    for inp in inputs:
                        if inp == "password":
                            code += "      password: await bcrypt.hash(password, 10),\n"
                        else:
                            code += f"      {inp}: {inp},\n"

                    code += """    }
  });
"""

                elif t == "login":
                    code += """
  const user = await prisma.user.findUnique({
    where: { email }
  });

  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }
"""

                elif t == "generate_token":
                    code += """
  const token = jwt.sign(
    { id: user.id },
    process.env.JWT_SECRET || 'dev_secret',
    { expiresIn: '7d' }
  );
"""

                elif t == "jwt_success":
                    code += """
  return res.json({ success: true, token });
"""

                elif t == "error":
                    code += f"""
  return res.status(400).json({ error: "{step['message']}" });
"""

                elif t == "success":
                    code += """
  return res.json({ success: true });
"""

            code += "\n});\n"

        code += """
app.listen(3000, () => console.log('MadiLang v0.3 running'));
"""

        return code
